pub fn get_codeset(charset_id: u8) -> Option<&'static phf::Map<u32, CharEntry>> {
    match charset_id {
        0x31 => Some(&CHARSET_31),
        0x32 => Some(&CHARSET_32),
        0x33 => Some(&CHARSET_33),
        0x34 => Some(&CHARSET_34),
        0x42 => Some(&CHARSET_42),
        0x45 => Some(&CHARSET_45),
        0x4E => Some(&CHARSET_4E),
        0x51 => Some(&CHARSET_51),
        0x53 => Some(&CHARSET_53),
        0x62 => Some(&CHARSET_62),
        0x67 => Some(&CHARSET_67),
        0x70 => Some(&CHARSET_70),
        _ => None,
    }
}

static ODD_MAP_TABLE: phf::Map<u32, u32> = phf_map! {
    0x21203Du32 => 0x2026,
    0x212040u32 => 0x201C,
    0x7F2014u32 => 0x2014,
    0x7F2019u32 => 0x2019,
    0x7F2020u32 => 0x201D,
    0x7F2122u32 => 0x2122,
};

pub fn odd_map_lookup(code_point: u32) -> Option<u32> {
    ODD_MAP_TABLE.get(&code_point).copied()
}
